#!/usr/bin/env bash
# Shared helpers for the stripeconnect-website deploy scripts.
# Sourced by every ensure-*.sh and deploy.sh. Must be idempotent.

set -euo pipefail

log()  { printf '\033[1;34m[deploy]\033[0m %s\n' "$*" >&2; }
warn() { printf '\033[1;33m[deploy]\033[0m %s\n' "$*" >&2; }
die()  { printf '\033[1;31m[deploy]\033[0m %s\n' "$*" >&2; exit 1; }

load_env() {
    local env="${1:-}"
    [[ -n "$env" ]] || die "Usage: $0 <preprod|prod>"
    local file
    file="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)/env/${env}.env"
    [[ -f "$file" ]] || die "Env file not found: $file"
    # shellcheck disable=SC1090
    set -a; source "$file"; set +a
    : "${AWS_REGION:?AWS_REGION missing}"
    : "${ACCOUNT_ID:?ACCOUNT_ID missing}"
    : "${CLUSTER_NAME:?CLUSTER_NAME missing}"
    export AWS_PAGER=""
}

# Usage: aws_exists "<describe cmd that fails silently when not found>"
aws_exists() {
    "$@" >/dev/null 2>&1
}

